import fs from "node:fs";
import os from "node:os";
import path from "node:path";
import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { getCurrentVersion, getInstalledSdks } from "./installedSdk.js";
let tmpDir;
beforeEach(() => {
    tmpDir = fs.mkdtempSync(path.join(os.tmpdir(), "bitfab-installed-"));
});
afterEach(() => {
    fs.rmSync(tmpDir, { recursive: true, force: true });
});
function write(relativePath, content) {
    const full = path.join(tmpDir, relativePath);
    fs.mkdirSync(path.dirname(full), { recursive: true });
    fs.writeFileSync(full, content);
}
describe("getInstalledSdks — no SDK", () => {
    it("returns empty when no manifests or lockfiles exist", () => {
        expect(getInstalledSdks(tmpDir)).toEqual([]);
    });
});
describe("getInstalledSdks — single-package TypeScript", () => {
    it("returns declared range from package.json when no lockfile", () => {
        write("package.json", JSON.stringify({ dependencies: { bitfab: "^0.10.0" } }));
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk).toMatchObject({
            language: "typescript",
            declaredVersion: "0.10.0",
            resolvedVersion: null,
            workspacePath: ".",
        });
        expect(getCurrentVersion(sdk)).toBe("0.10.0");
    });
    it("resolves from pnpm-lock.yaml", () => {
        write("package.json", JSON.stringify({ dependencies: { bitfab: "^0.9.0" } }));
        write("pnpm-lock.yaml", `lockfileVersion: '9.0'\n\npackages:\n\n  bitfab@0.9.5:\n    resolution: {integrity: sha512-abc}\n`);
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk.resolvedVersion).toBe("0.9.5");
    });
    it("resolves from package-lock.json v2/v3", () => {
        write("package.json", JSON.stringify({ dependencies: { bitfab: "^0.9.0" } }));
        write("package-lock.json", JSON.stringify({
            lockfileVersion: 3,
            packages: {
                "": { name: "app", dependencies: { bitfab: "^0.9.0" } },
                "node_modules/bitfab": { version: "0.9.7", resolved: "..." },
            },
        }));
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk.resolvedVersion).toBe("0.9.7");
    });
    it("resolves from yarn.lock", () => {
        write("package.json", JSON.stringify({ dependencies: { bitfab: "^0.9.0" } }));
        write("yarn.lock", `# yarn lockfile v1\n\nbitfab@^0.9.0, bitfab@^0.9.2:\n  version "0.9.8"\n  resolved "https://registry.yarnpkg.com/bitfab/-/bitfab-0.9.8.tgz"\n  integrity sha512-abc\n\nother-pkg@^1.0.0:\n  version "1.0.1"\n`);
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk.resolvedVersion).toBe("0.9.8");
    });
    it("falls back to node_modules/bitfab/package.json when no lockfile", () => {
        write("package.json", JSON.stringify({ dependencies: { bitfab: "^0.9.0" } }));
        write("node_modules/bitfab/package.json", JSON.stringify({ name: "bitfab", version: "0.9.6" }));
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk.resolvedVersion).toBe("0.9.6");
    });
    it("does not emit an entry when SDK is only in node_modules (not declared)", () => {
        write("package.json", JSON.stringify({ dependencies: {} }));
        write("node_modules/bitfab/package.json", JSON.stringify({ name: "bitfab", version: "0.9.3" }));
        expect(getInstalledSdks(tmpDir)).toEqual([]);
    });
    it("preserves pre-release metadata in declared range", () => {
        write("package.json", JSON.stringify({ dependencies: { bitfab: "^0.11.0-beta.1" } }));
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk.declaredVersion).toBe("0.11.0-beta.1");
    });
});
describe("getInstalledSdks — single-package Python / Ruby / Go", () => {
    it("Python: pyproject with no lockfile", () => {
        write("pyproject.toml", `dependencies = ["bitfab-py>=0.11.0"]`);
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk).toMatchObject({
            language: "python",
            declaredVersion: "0.11.0",
            resolvedVersion: null,
            workspacePath: ".",
        });
    });
    it("Python: resolves from uv.lock", () => {
        write("pyproject.toml", `dependencies = ["bitfab-py>=0.10"]`);
        write("uv.lock", `version = 1\n\n[[package]]\nname = "fastapi"\nversion = "0.100.0"\n\n[[package]]\nname = "bitfab-py"\nversion = "0.11.3"\n`);
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk.resolvedVersion).toBe("0.11.3");
    });
    it("Python: resolves from Pipfile.lock", () => {
        write("Pipfile", `[packages]\nbitfab-py = "*"\n`);
        write("pyproject.toml", `dependencies = ["bitfab-py"]`);
        write("Pipfile.lock", JSON.stringify({
            default: { "bitfab-py": { version: "==0.11.1", hashes: [] } },
        }));
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk.resolvedVersion).toBe("0.11.1");
    });
    it("Ruby: resolves from Gemfile.lock", () => {
        write("Gemfile", `source "https://rubygems.org"\ngem "bitfab", "~> 0.10"\n`);
        write("Gemfile.lock", `GEM\n  remote: https://rubygems.org/\n  specs:\n    bitfab (0.10.3)\n    rails (7.1.0)\n`);
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk.declaredVersion).toBe("0.10");
        expect(sdk.resolvedVersion).toBe("0.10.3");
    });
    it("Go: resolves from go.mod (exact pin)", () => {
        write("go.mod", `module example.com/app\n\ngo 1.21\n\nrequire github.com/Project-White-Rabbit/bitfab-go v0.5.3\n`);
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk).toMatchObject({
            language: "go",
            resolvedVersion: "0.5.3",
            workspacePath: ".",
        });
    });
});
describe("getInstalledSdks — monorepo workspaces", () => {
    it("pnpm workspaces: one entry per instrumented workspace", () => {
        write("package.json", JSON.stringify({ name: "monorepo" }));
        write("pnpm-workspace.yaml", `packages:\n  - 'apps/*'\n  - 'packages/*'\n`);
        write("pnpm-lock.yaml", `packages:\n\n  bitfab@0.11.0:\n    resolution: {integrity: sha512-x}\n`);
        write("apps/api/package.json", JSON.stringify({ name: "api", dependencies: { bitfab: "^0.11.0" } }));
        write("apps/web/package.json", JSON.stringify({ name: "web", dependencies: { react: "^18.0.0" } }));
        write("packages/core/package.json", JSON.stringify({ name: "core", devDependencies: { bitfab: "^0.11.0" } }));
        const sdks = getInstalledSdks(tmpDir);
        const paths = sdks.map((s) => s.workspacePath).sort();
        expect(paths).toEqual(["apps/api", "packages/core"]);
        for (const sdk of sdks) {
            expect(sdk.resolvedVersion).toBe("0.11.0");
        }
    });
    it("npm workspaces (package.json): emits per workspace", () => {
        write("package.json", JSON.stringify({ name: "root", workspaces: ["apps/*"] }));
        write("package-lock.json", JSON.stringify({
            lockfileVersion: 3,
            packages: { "node_modules/bitfab": { version: "0.9.9" } },
        }));
        write("apps/api/package.json", JSON.stringify({ name: "api", dependencies: { bitfab: "^0.9.0" } }));
        const sdks = getInstalledSdks(tmpDir);
        expect(sdks).toHaveLength(1);
        expect(sdks[0]).toMatchObject({
            workspacePath: "apps/api",
            resolvedVersion: "0.9.9",
        });
    });
    it("uv workspaces: emits per member", () => {
        write("pyproject.toml", `[project]\nname = "root"\n\n[tool.uv.workspace]\nmembers = ["apps/api", "services/worker"]\n`);
        write("uv.lock", `version = 1\n\n[[package]]\nname = "bitfab-py"\nversion = "0.11.5"\n`);
        write("apps/api/pyproject.toml", `[project]\nname = "api"\ndependencies = ["bitfab-py>=0.11"]\n`);
        write("services/worker/pyproject.toml", `[project]\nname = "worker"\ndependencies = ["bitfab-py>=0.10"]\n`);
        const sdks = getInstalledSdks(tmpDir);
        const paths = sdks.map((s) => s.workspacePath).sort();
        expect(paths).toEqual(["apps/api", "services/worker"]);
        for (const sdk of sdks) {
            expect(sdk.resolvedVersion).toBe("0.11.5");
        }
    });
    it("go.work: emits one entry per module", () => {
        write("go.work", `go 1.21\n\nuse (\n\t./apps/api\n\t./services/worker\n)\n`);
        write("apps/api/go.mod", `module example.com/api\n\ngo 1.21\n\nrequire github.com/Project-White-Rabbit/bitfab-go v0.5.3\n`);
        write("services/worker/go.mod", `module example.com/worker\n\ngo 1.21\n\nrequire github.com/Project-White-Rabbit/bitfab-go v0.5.2\n`);
        const sdks = getInstalledSdks(tmpDir);
        expect(sdks).toHaveLength(2);
        const byPath = Object.fromEntries(sdks.map((s) => [s.workspacePath, s.resolvedVersion]));
        expect(byPath["apps/api"]).toBe("0.5.3");
        expect(byPath["services/worker"]).toBe("0.5.2");
    });
    it("pnpm workspace:* resolves via root lockfile even without numeric range", () => {
        write("pnpm-workspace.yaml", `packages:\n  - 'packages/*'\n`);
        write("pnpm-lock.yaml", `packages:\n\n  bitfab@0.11.0:\n    resolution: {integrity: sha512-x}\n`);
        write("packages/app/package.json", JSON.stringify({
            name: "app",
            dependencies: { bitfab: "workspace:*" },
        }));
        const [sdk] = getInstalledSdks(tmpDir);
        expect(sdk.declaredVersion).toBeNull();
        expect(sdk.resolvedVersion).toBe("0.11.0");
        expect(sdk.workspacePath).toBe("packages/app");
    });
});
